import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer, CloudLightning, CloudSnow, Eye, Calendar, Clock, Navigation } from 'lucide-react';
import './App.css';

// તમારી પ્રોવાઇડ કરેલી અસલી API Key અહીં સેટ કરી દીધી છે
const API_KEY = "1d30e0668b384c4d133dc45fe617b03b"; 

function App() {
  const [city, setCity] = useState('Visnagar');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [hourlyData, setHourlyData] = useState([]);
  const [aqi, setAqi] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      // 1. Current Weather
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      const { lat, lon } = currentRes.data.coord;

      // 2. Air Quality Index (AQI)
      const aqiRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/air_pollution?lat=${lat}&lon=${lon}&appid=${API_KEY}`
      );
      setAqi(aqiRes.data.list[0].main.aqi);

      // 3. Forecast & Hourly Data
      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      setHourlyData(forecastRes.data.list.slice(0, 6)); 
      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

    } catch (err) {
      setError('આ નામે કોઈ શહેર મળ્યું નથી. સાચું નામ લખો.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  const getWeatherIcon = (main, size = 32) => {
    switch (main) {
      case 'Clear': return <Sun className="weather-glow text-amber" size={size} />;
      case 'Clouds': return <Cloud className="weather-glow text-slate" size={size} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="weather-glow text-cyan" size={size} />;
      case 'Thunderstorm': return <CloudLightning className="weather-glow text-purple" size={size} />;
      case 'Snow': return <CloudSnow className="weather-glow text-blue" size={size} />;
      default: return <Sun className="weather-glow text-amber" size={size} />;
    }
  };

  const getAQIBadge = (index) => {
    const status = {
      1: { text: 'ઉત્તમ હવામાં ફેરફાર', color: '#10b981' },
      2: { text: 'સાધારણ હવા', color: '#a855f7' },
      3: { text: 'મધ્યમ પ્રદૂષણ', color: '#f59e0b' },
      4: { text: 'ખરાબ હવામાન', color: '#f87171' },
      5: { text: 'ગંભીર પ્રદૂષણ', color: '#ef4444' }
    };
    return status[index] || { text: 'નથી ઉપલબ્ધ', color: '#fff' };
  };

  return (
    <div className="premium-weather-app">
      <div className="atmosphere-bg-glow"></div>

      <div className="app-viewport">
        {/* Top Minimal Navigation */}
        <header className="premium-header">
          <div className="brand-title">Sky<span>vibe</span></div>

          <form onSubmit={handleSearch} className="minimal-search-bar">
            <input 
              type="text" 
              placeholder="બીજું શહેર શોધો..." 
              value={city}
              onChange={(e) => setCity(e.target.value)}
            />
            <button type="submit"><Search size={16} /></button>
          </form>
        </header>

        {loading && <div className="loader-overlay"><div className="pulse-loader"></div><p>લાઇવ ડેટા લોડ થાય છે...</p></div>}
        {error && <div className="error-card">{error}</div>}

        {weatherData && !loading && !error && (
          <div className="dynamic-workspace animate-fade-in">

            {/* 1. HERO HUB (Apple Weather Style) */}
            <section className="hero-hub">
              <div className="hero-main-info">
                <div className="city-geo">
                  <Navigation size={18} className="geo-icon" />
                  <h2>{weatherData.name}</h2>
                  <span className="country-pill">{weatherData.sys.country}</span>
                </div>
                <h1 className="ultra-temp">{Math.round(weatherData.main.temp)}°</h1>
                <p className="condition-status">{weatherData.weather[0].description}</p>
              </div>
              <div className="hero-visual">
                {getWeatherIcon(weatherData.weather[0].main, 150)}
              </div>
            </section>

            {/* 2. HOURLY HORIZON (Horizontal Slider) */}
            <section className="glass-panel hourly-horizon">
              <div className="panel-title"><Clock size={15} /> <span>આજના આગામી કલાકોની આગાહી</span></div>
              <div className="horizontal-scroll-track">
                {hourlyData.map((hour, idx) => (
                  <div key={idx} className="hourly-column-node">
                    <span className="h-time">{hour.dt_txt.split(' ')[1].substring(0, 5)}</span>
                    <div className="h-icon-box">{getWeatherIcon(hour.weather[0].main, 26)}</div>
                    <span className="h-temp-val">{Math.round(hour.main.temp)}°</span>
                  </div>
                ))}
              </div>
            </section>

            {/* 3. METRIC & FORECAST GRID SPLIT */}
            <div className="split-layout-grid">

              {/* Analytics Matrix */}
              <div className="sub-grid-metrics">
                <div className="glass-panel metric-cube">
                  <div className="m-label"><Thermometer size={14} /> <span>Feels Like</span></div>
                  <h3>{Math.round(weatherData.main.feels_like)}°C</h3>
                </div>

                <div className="glass-panel metric-cube">
                  <div className="m-label"><Droplets size={14} /> <span>Humidity</span></div>
                  <h3>{weatherData.main.humidity}%</h3>
                </div>

                <div className="glass-panel metric-cube">
                  <div className="m-label"><Wind size={14} /> <span>Wind Velocity</span></div>
                  <h3>{weatherData.wind.speed} <span className="m-unit">m/s</span></h3>
                </div>

                <div className="glass-panel metric-cube">
                  <div className="m-label"><Eye size={14} /> <span>Visibility</span></div>
                  <h3>{(weatherData.visibility / 1000).toFixed(1)} <span className="m-unit">km</span></h3>
                </div>

                {/* AQI Integration Card */}
                <div className="glass-panel aqi-horizontal-strip">
                  <div className="aqi-left">
                    <span className="aqi-title">હવાની ગુણવત્તા (AQI)</span>
                    <p style={{ color: getAQIBadge(aqi).color }}>{getAQIBadge(aqi).text}</p>
                  </div>
                  <div className="aqi-right-badge" style={{ borderColor: getAQIBadge(aqi).color, color: getAQIBadge(aqi).color }}>
                    Index {aqi}
                  </div>
                </div>
              </div>

              {/* Weekly Extended Outlook */}
              <section className="glass-panel extended-outlook">
                <div className="panel-title"><Calendar size={15} /> <span>5-દિવસીય વિસ્તૃત આંકડા</span></div>
                <div className="weekly-rows-stack">
                  {forecastData.map((day, idx) => (
                    <div key={idx} className="weekly-card-row">
                      <span className="w-day-name">
                        {new Date(day.dt * 1000).toLocaleDateString('gu-IN', { weekday: 'short' })}
                      </span>
                      <div className="w-icon-status-group">
                        {getWeatherIcon(day.weather[0].main, 22)}
                        <span className="w-condition-desc">{day.weather[0].main}</span>
                      </div>
                      <span className="w-temp-highlight">{Math.round(day.main.temp)}°C</span>
                    </div>
                  ))}
                </div>
              </section>

            </div>

          </div>
        )}
      </div>
    </div>
  );
}

export default App;
